    public Object parseDepositWithdrawFees(Object response, Object... optionalArgs)
    {
        //
        //    {
        //        "1INCH": {
        //            "is_depositable": true,
        //            "is_withdrawal": true,
        //            "ticker": "1INCH",
        //            "name": "1inch",
        //            "providers": [],
        //            "withdraw": {
        //                "max_amount": "0",
        //                "min_amount": "21.5",
        //                "fixed": "17.5",
        //                "flex": null
        //            },
        //            "deposit": {
        //                "max_amount": "0",
        //                "min_amount": "19.5",
        //                "fixed": null,
        //                "flex": null
        //            }
        //        },
        //        "WBT (ERC20)": {
        //            "is_depositable": true,
        //            "is_withdrawal": true,
        //            "ticker": "WBT",
        //            "name": "WhiteBIT Token",
        //            "providers": [],
        //            "withdraw": { max_amount: "0", min_amount: "0.7", fixed: "0.253", flex: null },
        //            "deposit": { max_amount: "0", min_amount: "0.35", fixed: null, flex: null }
        //        },
        //        "WBT (TRC20)": {
        //            "is_depositable": true,
        //            "is_withdrawal": true,
        //            "ticker": "WBT",
        //            "name": "WhiteBIT Token",
        //            "providers": [],
        //            "withdraw": { max_amount: "0", min_amount: "1.5", fixed: "0.075", flex: null },
        //            "deposit": { max_amount: "0", min_amount: "0.75", fixed: null, flex: null }
        //        },
        //        ...
        //    }
        //
        Object codes = Helpers.getArg(optionalArgs, 0, null);
        Object currencyIdKey = Helpers.getArg(optionalArgs, 1, null);
        Object depositWithdrawFees = new java.util.HashMap<String, Object>() {{}};
        codes = this.marketCodes(codes);
        Object currencyIds = Helpers.objectKeys(response);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencyIds)); i++)
        {
            Object entry = Helpers.GetValue(currencyIds, i);
            Object splitEntry = Helpers.split(entry, " ");
            Object currencyId = Helpers.GetValue(splitEntry, 0);
            Object feeInfo = Helpers.GetValue(response, entry);
            Object code = this.safeCurrencyCode(currencyId);
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(codes, null))) || Helpers.isTrue((this.inArray(code, codes)))))
            {
                Object depositWithdrawFee = this.safeValue(depositWithdrawFees, code);
                if (Helpers.isTrue(Helpers.isEqual(depositWithdrawFee, null)))
                {
                    Helpers.addElementToObject(depositWithdrawFees, code, this.depositWithdrawFee(new java.util.HashMap<String, Object>() {{}}));
                }
                Helpers.addElementToObject(Helpers.GetValue(Helpers.GetValue(depositWithdrawFees, code), "info"), entry, feeInfo);
                Object networkId = this.safeString(splitEntry, 1);
                Object withdraw = this.safeValue(feeInfo, "withdraw");
                Object deposit = this.safeValue(feeInfo, "deposit");
                Object withdrawFee = this.safeNumber(withdraw, "fixed");
                Object depositFee = this.safeNumber(deposit, "fixed");
                final Object finalWithdrawFee = withdrawFee;
                Object withdrawResult = new java.util.HashMap<String, Object>() {{
                    put( "fee", finalWithdrawFee );
                    put( "percentage", ((Helpers.isTrue((!Helpers.isEqual(finalWithdrawFee, null))))) ? false : null );
                }};
                final Object finalDepositFee = depositFee;
                Object depositResult = new java.util.HashMap<String, Object>() {{
                    put( "fee", finalDepositFee );
                    put( "percentage", ((Helpers.isTrue((!Helpers.isEqual(finalDepositFee, null))))) ? false : null );
                }};
                if (Helpers.isTrue(!Helpers.isEqual(networkId, null)))
                {
                    Object networkLength = ((String)networkId).length();
                    networkId = Helpers.slice(networkId, 1, Helpers.subtract(networkLength, 1));
                    Object networkCode = this.networkIdToCode(networkId, code);
                    Helpers.addElementToObject(Helpers.GetValue(Helpers.GetValue(depositWithdrawFees, code), "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "withdraw", withdrawResult );
    put( "deposit", depositResult );
}});
                } else
                {
                    Helpers.addElementToObject(Helpers.GetValue(depositWithdrawFees, code), "withdraw", withdrawResult);
                    Helpers.addElementToObject(Helpers.GetValue(depositWithdrawFees, code), "deposit", depositResult);
                }
            }
        }
        Object depositWithdrawCodes = Helpers.objectKeys(depositWithdrawFees);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(depositWithdrawCodes)); i++)
        {
            Object code = Helpers.GetValue(depositWithdrawCodes, i);
            Object currency = this.currency(code);
            Helpers.addElementToObject(depositWithdrawFees, code, this.assignDefaultDepositWithdrawFees(Helpers.GetValue(depositWithdrawFees, code), currency));
        }
        return depositWithdrawFees;
    }

    /**
     * @method
     * @name whitebit#fetchTradingFees
     * @description fetch the trading fees for multiple markets
     * @see https://docs.whitebit.com/public/http-v4/#asset-status-list
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.v4PublicGetAssets(parameters)).join();
            //
            //      {
            //          "1INCH": {
            //              "name": "1inch",
            //              "unified_cryptoasset_id": "8104",
            //              "can_withdraw": true,
            //              "can_deposit": true,
            //              "min_withdraw": "33",
            //              "max_withdraw": "0",
            //              "maker_fee": "0.1",
            //              "taker_fee": "0.1",
            //              "min_deposit": "30",
            //              "max_deposit": "0"
            //            },
            //            ...
            //      }
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.symbols)); i++)
            {
                Object symbol = Helpers.GetValue(this.symbols, i);
                Object market = this.market(symbol);
                Object fee = this.safeValue(response, Helpers.GetValue(market, "baseId"), new java.util.HashMap<String, Object>() {{}});
                Object makerFee = this.safeString(fee, "maker_fee");
                Object takerFee = this.safeString(fee, "taker_fee");
                makerFee = Precise.stringDiv(makerFee, "100");
                takerFee = Precise.stringDiv(takerFee, "100");
                final Object finalMakerFee = makerFee;
                final Object finalTakerFee = takerFee;
                Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", fee );
        put( "symbol", Helpers.GetValue(market, "symbol") );
        put( "percentage", true );
        put( "tierBased", false );
        put( "maker", WhitebitCore.this.parseNumber(finalMakerFee) );
        put( "taker", WhitebitCore.this.parseNumber(finalTakerFee) );
    }});
            }
            return result;
        });

    }

    /**
     * @method
     * @name whitebit#fetchTradingLimits
     * @description fetch the trading limits for a market
     * @see https://docs.whitebit.com/public/http-v4/#market-info
     * @param {string[]|undefined} symbols unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [trading limits structure]{@link https://docs.ccxt.com/?id=trading-limits-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTradingLimits(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            //
            // Trading limits are derived from market information already loaded by loadMarkets()
            // Market structure includes:
            //     {
            //         "id": "BTC_USDT",                    // Market ID
            //         "symbol": "BTC/USDT",                // Unified symbol
            //         "base": "BTC",                       // Base currency
            //         "quote": "USDT",                     // Quote currency
            //         "active": true,                      // Market active status
            //         "type": "spot",                      // Market type
            //         "spot": true,                        // Spot trading enabled
            //         "margin": false,                     // Margin trading enabled
            //         "future": false,                     // Futures trading enabled
            //         "option": false,                     // Options trading enabled
            //         "contract": false,                   // Contract trading enabled
            //         "settle": undefined,                 // Settlement currency
            //         "settleId": undefined,               // Settlement currency ID
            //         "contractSize": undefined,           // Contract size
            //         "linear": undefined,                 // Linear contract
            //         "inverse": undefined,                // Inverse contract
            //         "limits": {                          // Trading limits
            //             "amount": {                      // Amount limits
            //                 "min": 0.00001,              // Minimum amount
            //                 "max": 1000000               // Maximum amount
            //             },
            //             "price": {                       // Price limits
            //                 "min": 0.01,                 // Minimum price
            //                 "max": 1000000               // Maximum price
            //             },
            //             "cost": {                        // Cost limits
            //                 "min": 5.0,                  // Minimum cost
            //                 "max": 10000000              // Maximum cost
            //             }
            //         },
            //         "precision": {                       // Precision settings
            //             "amount": 5,                     // Amount precision
            //             "price": 2                       // Price precision
            //         },
            //         "taker": 0.001,                      // Taker fee
            //         "maker": 0.001,                      // Maker fee
            //         "percentage": true,                  // Fee percentage
            //         "tierBased": false                   // Tier-based fees
            //     }
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            // Process all markets from the loaded markets cache
            Object marketIds = Helpers.objectKeys(this.markets);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object market = Helpers.GetValue(this.markets, marketId);
                if (Helpers.isTrue(!Helpers.isTrue(market) || !Helpers.isTrue(Helpers.GetValue(market, "symbol"))))
                {
                    continue;
                }
                Object symbol = Helpers.GetValue(market, "symbol");
                // Filter by symbols if specified
                if (Helpers.isTrue(symbols))
                {
                    Object symbolFound = false;
                    for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(symbols)); j++)
                    {
                        if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(symbols, j), symbol)))
                        {
                            symbolFound = true;
                            break;
                        }
                    }
                    if (!Helpers.isTrue(symbolFound))
                    {
                        continue;
                    }
                }
                // Extract trading limits
                Object limits = this.safeDict(market, "limits");
                Object amountLimits = this.safeDict(limits, "amount");
                Object priceLimits = this.safeDict(limits, "price");
                Object costLimits = this.safeDict(limits, "cost");
                // Validate that all required limits exist and are valid numbers
                Object hasAmountLimits = Helpers.isTrue(Helpers.isTrue(amountLimits) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(amountLimits, "min"), null))) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(amountLimits, "max"), null));
                Object hasPriceLimits = Helpers.isTrue(Helpers.isTrue(priceLimits) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(priceLimits, "min"), null))) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(priceLimits, "max"), null));
                Object hasCostLimits = Helpers.isTrue(Helpers.isTrue(costLimits) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(costLimits, "min"), null))) && Helpers.isTrue(!Helpers.isEqual(this.safeNumber(costLimits, "max"), null));
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(hasAmountLimits) && Helpers.isTrue(hasPriceLimits)) && Helpers.isTrue(hasCostLimits)))
                {
                    final Object finalAmountLimits = amountLimits;
                    final Object finalPriceLimits = priceLimits;
                    final Object finalCostLimits = costLimits;
                    Helpers.addElementToObject(result, symbol, new java.util.HashMap<String, Object>() {{
        put( "info", market );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "amount", new java.util.HashMap<String, Object>() {{
                put( "min", WhitebitCore.this.safeNumber(finalAmountLimits, "min") );
                put( "max", WhitebitCore.this.safeNumber(finalAmountLimits, "max") );
            }} );
            put( "price", new java.util.HashMap<String, Object>() {{
                put( "min", WhitebitCore.this.safeNumber(finalPriceLimits, "min") );
                put( "max", WhitebitCore.this.safeNumber(finalPriceLimits, "max") );
            }} );
            put( "cost", new java.util.HashMap<String, Object>() {{
                put( "min", WhitebitCore.this.safeNumber(finalCostLimits, "min") );
                put( "max", WhitebitCore.this.safeNumber(finalCostLimits, "max") );
            }} );
        }} );
    }});
                }
            }
            return result;
        });

    }

    /**
     * @method
     * @name whitebit#fetchFundingLimits
     * @description fetch the deposit and withdrawal limits for a currency
     * @see https://docs.whitebit.com/public/http-v4/#asset-status-list
     * @see https://docs.whitebit.com/public/http-v4/#fee
     * @param {string[]|undefined} codes unified currency codes
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [funding limits structure]{@link https://docs.ccxt.com/?id=funding-limits-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingLimits(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object codes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            // Fetch both currencies and fees data for comprehensive funding limits
            var currenciesDatafeesDataVariable = (Helpers.promiseAll(new java.util.ArrayList<Object>(java.util.Arrays.asList(this.fetchCurrenciesAsync(), this.v4PublicGetFee(parameters))))).join();
            var currenciesData = ((java.util.List<Object>) currenciesDatafeesDataVariable).get(0);
            var feesData = ((java.util.List<Object>) currenciesDatafeesDataVariable).get(1);
            //
            // Currencies response structure (from fetchCurrencies):
            //     {
            //         "BTC": {
            //             "id": "BTC",                          // Currency ID
            //             "code": "BTC",                        // Currency code
            //             "name": "Bitcoin",                    // Currency name
            //             "active": true,                       // Currency active status
            //             "type": "crypto",                     // Currency type
            //             "precision": 8,                       // Currency precision
            //             "limits": {                           // Currency limits
            //                 "deposit": {                      // Deposit limits
            //                     "min": 0.00001,               // Minimum deposit
            //                     "max": 1000000                // Maximum deposit
            //                 },
            //                 "withdraw": {                     // Withdrawal limits
            //                     "min": 0.00001,               // Minimum withdrawal
            //                     "max": 1000000                // Maximum withdrawal
            //                 }
            //             },
            //             "networks": {                         // Network-specific limits
            //                 "BTC": {
            //                     "limits": {
            //                         "deposit": { "min": "0.001" },
            //                         "withdraw": { "min": "0.002" }
            //                     }
            //                 }
            //             },
            //             "info": { ... }                       // Original API response
            //         }
            //     }
            //
            // Fees response structure (from /api/v4/public/fee):
            //     {
            //         "USDT (ERC20)": {
            //             "ticker": "USDT",
            //             "name": "Tether US",
            //             "deposit": {
            //                 "min_amount": "0.0005",
            //                 "max_amount": "0.1",
            //                 "fixed": "0.0005",
            //                 "flex": {
            //                     "min_fee": "100",
            //                     "max_fee": "1000",
            //                     "percent": "10"
            //                 }
            //             },
            //             "withdraw": {
            //                 "min_amount": "0.001",
            //                 "max_amount": "0",
            //                 "fixed": null,
            //                 "flex": null
            //             }
            //         }
            //     }
            //
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object currencyKeys = Helpers.objectKeys(currenciesData);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencyKeys)); i++)
            {
                Object code = Helpers.GetValue(currencyKeys, i);
                Object currency = Helpers.GetValue(currenciesData, code);
                if (!Helpers.isTrue(currency))
                {
                    continue;
                }
                if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(codes, null)) && !Helpers.isTrue(this.inArray(code, codes))))
                {
                    continue;
                }
                // Find corresponding fee data for this currency
                Object feeData = null;
                Object feeKeys = Helpers.objectKeys(feesData);
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(feeKeys)); j++)
                {
                    Object feeKey = Helpers.GetValue(feeKeys, j);
                    Object fee = Helpers.GetValue(feesData, feeKey);
                    if (Helpers.isTrue(Helpers.isTrue(fee) && Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(fee, "ticker"), code))))
                    {
                        feeData = fee;
                        break;
                    }
                }
                // Build comprehensive funding limits
                Object limits = new java.util.HashMap<String, Object>() {{
                    put( "deposit", new java.util.HashMap<String, Object>() {{
                        put( "min", Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(currency, "limits"), "deposit"), "min") );
                        put( "max", Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(currency, "limits"), "deposit"), "max") );
                    }} );
                    put( "withdraw", new java.util.HashMap<String, Object>() {{
                        put( "min", Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(currency, "limits"), "withdraw"), "min") );
                        put( "max", Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(currency, "limits"), "withdraw"), "max") );
                    }} );
                }};
                // Add fee information if available
                if (Helpers.isTrue(feeData))
                {
                    Object depositFee = Helpers.GetValue(feeData, "deposit");
                    Object withdrawFee = Helpers.GetValue(feeData, "withdraw");
                    if (Helpers.isTrue(depositFee))
                    {
                        Object depositFeeData = new java.util.HashMap<String, Object>() {{
                            put( "fixed", WhitebitCore.this.safeNumber(depositFee, "fixed") );
                        }};
                        if (Helpers.isTrue(Helpers.GetValue(depositFee, "flex")))
                        {
                            Helpers.addElementToObject(depositFeeData, "flex", new java.util.HashMap<String, Object>() {{
        put( "min", WhitebitCore.this.safeNumber(Helpers.GetValue(depositFee, "flex"), "min_fee") );
        put( "max", WhitebitCore.this.safeNumber(Helpers.GetValue(depositFee, "flex"), "max_fee") );
        put( "percent", WhitebitCore.this.safeNumber(Helpers.GetValue(depositFee, "flex"), "percent") );
    }});
                        }
                        Helpers.addElementToObject(Helpers.GetValue(limits, "deposit"), "fee", depositFeeData);
                    }
                    if (Helpers.isTrue(withdrawFee))
                    {
                        Object withdrawFeeData = new java.util.HashMap<String, Object>() {{
                            put( "fixed", WhitebitCore.this.safeNumber(withdrawFee, "fixed") );
                        }};
                        if (Helpers.isTrue(Helpers.GetValue(withdrawFee, "flex")))
                        {
                            Helpers.addElementToObject(withdrawFeeData, "flex", new java.util.HashMap<String, Object>() {{
        put( "min", WhitebitCore.this.safeNumber(Helpers.GetValue(withdrawFee, "flex"), "min_fee") );
        put( "max", WhitebitCore.this.safeNumber(Helpers.GetValue(withdrawFee, "flex"), "max_fee") );
        put( "percent", WhitebitCore.this.safeNumber(Helpers.GetValue(withdrawFee, "flex"), "percent") );
    }});
                        }
                        Helpers.addElementToObject(Helpers.GetValue(limits, "withdraw"), "fee", withdrawFeeData);
                    }
                }
                // Add network-specific limits if available
                if (Helpers.isTrue(Helpers.GetValue(currency, "networks")))
                {
                    Helpers.addElementToObject(limits, "networks", Helpers.GetValue(currency, "networks"));
                }
                Helpers.addElementToObject(result, code, new java.util.HashMap<String, Object>() {{
        put( "info", currency );
        put( "limits", limits );
    }});
            }
            return result;
        });

    }

    /**
     * @method
     * @name whitebit#fetchTicker
     * @description fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific market
     * @see https://docs.whitebit.com/public/http-v4/#market-activity
     * @param {string} symbol unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTicker(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.v1PublicGetTicker(this.extend(request, parameters))).join();
            //
            //      {
            //         "success":true,
            //         "message":"",
            //         "result": {
            //             "bid":"0.021979",
            //             "ask":"0.021996",
            //             "open":"0.02182",
            //             "high":"0.022039",
            //             "low":"0.02161",
            //             "last":"0.021987",
            //             "volume":"2810.267",
            //             "deal":"61.383565474",
            //             "change":"0.76",
            //         },
            //     }
            //
            Object ticker = this.safeDict(response, "result", new java.util.HashMap<String, Object>() {{}});
            return this.parseTicker(ticker, market);
        });

    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //  FetchTicker (v1)
        //
        //    {
        //        "bid": "0.021979",
        //        "ask": "0.021996",
        //        "open": "0.02182",
        //        "high": "0.022039",
        //        "low": "0.02161",
        //        "last": "0.021987",
        //        "volume": "2810.267",
        //        "deal": "61.383565474",
        //        "change": "0.76",
        //    }
        //
        // FetchTickers (v4)
        //
        //    "BCH_RUB": {
        //        "base_id": 1831,
        //        "quote_id": 0,
        //        "last_price": "32830.21",
        //        "quote_volume": "1494659.8024096",
        //        "base_volume": "46.1083",
        //        "isFrozen": false,
        //        "change": "2.12" // in percent
        //    }
        //
        // WS market_update
        //
        //     {
        //         "open": "52853.04",
        //         "close": "55913.88",
        //         "high": "56272",
        //         "low": "49549.67",
        //         "volume": "57331.067185",
        //         "deal": "3063860382.42985338",
        //         "last": "55913.88",
        //         "period": 86400
        //     }
        // v2
        //   {
        //       lastUpdateTimestamp: '2025-01-02T09:16:36.000Z',
        //       tradingPairs: 'ARB_USDC',
        //       lastPrice: '0.7727',
        //       lowestAsk: '0.7735',
        //       highestBid: '0.7732',
        //       baseVolume24h: '1555793.74',
        //       quoteVolume24h: '1157602.622406',
        //       tradesEnabled: true
        //   }
        //
        // v4PublicGetFutures
        //     {
        //         "ticker_id": "0G_PERP",
        //         "stock_currency": "0G",
        //         "money_currency": "USDT",
        //         "last_price": "0.6065",
        //         "stock_volume": "2563218",
        //         "money_volume": "1587952.6137",
        //         "bid": "0.6065",
        //         "ask": "0.6077",
        //         "high": "0.6472",
        //         "low": "0.6045",
        //         "product_type": "Perpetual",
        //         "open_interest": "3721488",
        //         "index_price": "0.61",
        //         "index_name": "0G future contract",
        //         "index_currency": "0G",
        //         "funding_rate": "-0.00000778",
        //         "next_funding_rate_timestamp": "1772467200000",
        //         "brackets": {
        //             "1": 0,
        //             "10": 0,
        //             "100": 0,
        //             "2": 0,
        //             "20": 4000,
        //             "3": 0,
        //             "5": 0,
        //             "50": 800
        //         },
        //         "max_leverage": 50,
        //         "funding_interval_minutes": 240
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(ticker, "tradingPairs", "ticker_id");
        market = this.safeMarket(marketId, market);
        // last price is provided as "last" or "last_price"
        Object last = this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("last", "last_price", "lastPrice")));
        // if "close" is provided, use it, otherwise use <last>
        Object close = this.safeString(ticker, "close", last);
        final Object finalMarket = market;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "timestamp", null );
            put( "datetime", null );
            put( "high", WhitebitCore.this.safeString(ticker, "high") );
            put( "low", WhitebitCore.this.safeString(ticker, "low") );
            put( "bid", WhitebitCore.this.safeString2(ticker, "bid", "highestBid") );
            put( "bidVolume", null );
            put( "ask", WhitebitCore.this.safeString2(ticker, "ask", "lowestAsk") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", WhitebitCore.this.safeString(ticker, "open") );
            put( "close", close );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", WhitebitCore.this.safeString(ticker, "change") );
            put( "average", null );
            put( "baseVolume", WhitebitCore.this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("base_volume", "volume", "baseVolume24h", "stock_volume"))) );
            put( "quoteVolume", WhitebitCore.this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("quote_volume", "deal", "quoteVolume24h", "money_volume"))) );
            put( "indexPrice", WhitebitCore.this.safeString(ticker, "index_price") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name whitebit#fetchOrder
     * @description fetches information on an order by the id
     * @see https://docs.whitebit.com/private/http-trade-v4/#query-unexecutedactive-orders
     * @see https://docs.whitebit.com/private/http-trade-v4/#query-executed-orders
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.checkActive] whether to check active orders (default: true)
     * @param {boolean} [params.checkExecuted] whether to check executed orders (default: true)
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            // Extract control parameters from params
            Object checkActive = this.safeBool(parameters, "checkActive", true);
            Object checkExecuted = this.safeBool(parameters, "checkExecuted", true);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "orderId", id );
            }};
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "market", Helpers.GetValue(market, "id"));
            }
            // Try active orders first (if enabled)
            if (Helpers.isTrue(checkActive))
            {
                try
                {
                    Object response = (this.v4PrivatePostOrders(this.extend(request, parameters))).join();
                    // Search for order in active orders response (array format)
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
                    {
                        Object order = Helpers.GetValue(response, i);
                        Object orderId = this.safeString(order, "orderId");
                        if (Helpers.isTrue(Helpers.isEqual(orderId, id)))
                        {
                            Object marketId = this.safeString(order, "market");
                            Object marketNew = this.safeMarket(marketId, null, "_");
                            return this.parseOrder(order, marketNew);
                        }
                    }
                } catch(Exception error)
                {
                    if (!Helpers.isTrue((Helpers.isInstance(error, OrderNotFound.class))))
                    {
                        throw error;
                    }
                }
            }
            // Try executed orders (if enabled)
            if (Helpers.isTrue(checkExecuted))
            {
                try
                {
                    Object response = (this.v4PrivatePostTradeAccountOrderHistory(this.extend(request, parameters))).join();
                    // Search for order in executed orders response (object format)
                    Object marketIds = Helpers.objectKeys(response);
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
                    {
                        Object marketId = Helpers.GetValue(marketIds, i);
                        Object marketNew = this.safeMarket(marketId, null, "_");
                        Object orders = Helpers.GetValue(response, marketId);
                        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(orders)); j++)
                        {
                            Object order = Helpers.GetValue(orders, j);
                            Object orderId = this.safeString(order, "id");
                            if (Helpers.isTrue(Helpers.isEqual(orderId, id)))
                            {
                                return this.parseOrder(order, marketNew);
                            }
                        }
                    }
                } catch(Exception error)
                {
                    if (!Helpers.isTrue((Helpers.isInstance(error, OrderNotFound.class))))
                    {
                        throw error;
                    }
                }
            }
            throw new OrderNotFound((String)Helpers.add(Helpers.add(this.id, " fetchOrder() order not found: "), id)) ;
        });

    }

    /**
     * @method
     * @name whitebit#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://docs.whitebit.com/public/http-v4/#market-activity
     * @param {string[]} [symbols] unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.type] 'spot' or 'swap' - default is 'spot'. If type is 'swap', it will call v4PublicGetFutures
     * @param {string} [params.method] either v2PublicGetTicker or v4PublicGetTicker or v4PublicGetFutures - default is v4PublicGetTicker for spot and mixed markets, and v4PublicGetFutures for swap
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object onlyContractSymbols = true;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
                {
                    Object symbol = Helpers.GetValue(symbols, i);
                    Object market = this.market(symbol);
                    if (!Helpers.isTrue((Helpers.GetValue(market, "contract"))))
                    {
                        onlyContractSymbols = false;
                        break;
                    }
                }
            } else
            {
                onlyContractSymbols = false;
            }
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchTickers", null, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object method = null;
            var methodparametersVariable = this.handleOptionAndParams(parameters, "fetchTickers", "method", method);
            method = ((java.util.List<Object>) methodparametersVariable).get(0);
            parameters = ((java.util.List<Object>) methodparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(method, null)))
            {
                // if the user did not specify a method, choose it based on market type and symbols
                if (Helpers.isTrue(Helpers.isTrue(onlyContractSymbols) || Helpers.isTrue((Helpers.isEqual(marketType, "swap")))))
                {
                    method = "v4PublicGetFutures";
                } else
                {
                    method = "v4PublicGetTicker";
                }
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(method, "v4PublicGetTicker")))
            {
                //
                //      "BCH_RUB": {
                //          "base_id":1831,
                //          "quote_id":0,
                //          "last_price":"32830.21",
                //          "quote_volume":"1494659.8024096",
                //          "base_volume":"46.1083",
                //          "isFrozen":false,
                //          "change":"2.12"
                //      },
                //
                response = (this.v4PublicGetTicker(parameters)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(method, "v4PublicGetFutures")))
            {
                //
                //     {
                //         "success": true,
                //         "message": null,
                //         "result": [
                //             {
                //                 "ticker_id": "0G_PERP",
                //                 "stock_currency": "0G",
                //                 "money_currency": "USDT",
                //                 "last_price": "0.6065",
                //                 "stock_volume": "2563218",
                //                 "money_volume": "1587952.6137",
                //                 "bid": "0.6065",
                //                 "ask": "0.6077",
                //                 "high": "0.6472",
                //                 "low": "0.6045",
                //                 "product_type": "Perpetual",
                //                 "open_interest": "3721488",
                //                 "index_price": "0.61",
                //                 "index_name": "0G future contract",
                //                 "index_currency": "0G",
                //                 "funding_rate": "-0.00000778",
                //                 "next_funding_rate_timestamp": "1772467200000",
                //                 "brackets": {
                //                     "1": 0,
                //                     "10": 0,
                //                     "100": 0,
                //                     "2": 0,
                //                     "20": 4000,
                //                     "3": 0,
                //                     "5": 0,
                //                     "50": 800
                //                 },
                //                 "max_leverage": 50,
                //                 "funding_interval_minutes": 240
                //             }
                //         ]
                //     }
                //
                response = (this.v4PublicGetFutures(parameters)).join();
            } else
            {
                response = (this.v2PublicGetTicker(parameters)).join();
            }
            Object resultList = this.safeList(response, "result");
            if (Helpers.isTrue(!Helpers.isEqual(resultList, null)))
            {
                return this.parseTickers(resultList, symbols);
            }
            Object marketIds = Helpers.objectKeys(response);
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object market = this.safeMarket(marketId);
                Object ticker = this.parseTicker(Helpers.GetValue(response, marketId), market);
                Object symbol = Helpers.GetValue(ticker, "symbol");
                Helpers.addElementToObject(result, ((String)symbol), ticker);
            }
            return this.filterByArrayTickers(result, "symbol", symbols);
        });

    }

