    /**
     * @method
     * @name whitebit#fetchTrades
     * @description get the list of most recent trades for a particular symbol
     * @see https://docs.whitebit.com/public/http-v4/#recent-trades
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.v4PublicGetTradesMarket(this.extend(request, parameters))).join();
            //
            //      [
            //          {
            //              "tradeID": 158056419,
            //              "price": "9186.13",
            //              "quote_volume": "0.0021",
            //              "base_volume": "9186.13",
            //              "trade_timestamp": 1594391747,
            //              "type": "sell"
            //          },
            //      ],
            //
            return this.parseTrades(response, market, since, limit);
        });

    }

    /**
     * @method
     * @name whitebit#fetchMyTrades
     * @description fetch all trades made by the user
     * @see https://docs.whitebit.com/private/http-trade-v4/#query-executed-order-history
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = null;
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "market", Helpers.GetValue(market, "id"));
            }
            Object response = (this.v4PrivatePostTradeAccountExecutedHistory(this.extend(request, parameters))).join();
            //
            // when no symbol is provided
            //
            //   {
            //       "USDC_USDT":[
            //          {
            //             "id":"1343815269",
            //             "clientOrderId":"",
            //             "time":"1641051917.532965",
            //             "side":"sell",
            //             "role":"2",
            //             "amount":"9.986",
            //             "price":"0.9995",
            //             "deal":"9.981007",
            //             "fee":"0.009981007",
            //             "orderId":"58166729555"
            //          },
            //       ]
            //   }
            //
            // when a symbol is provided
            //
            //     [
            //         {
            //             "id": 1343815269,
            //             "clientOrderId": '',
            //             "time": 1641051917.532965,
            //             "side": "sell",
            //             "role": 2,
            //             "amount": "9.986",
            //             "price": "0.9995",
            //             "deal": "9.981007",
            //             "fee": "0.009981007",
            //             "orderId": 58166729555,
            //         },
            //     ]
            //
            if (Helpers.isTrue(Helpers.isArray(response)))
            {
                return this.parseTrades(response, market, since, limit);
            } else
            {
                Object results = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                Object keys = Helpers.objectKeys(response);
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
                {
                    Object marketId = Helpers.GetValue(keys, i);
                    Object marketNew = this.safeMarket(marketId, null, "_");
                    Object rawTrades = this.safeValue(response, marketId, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                    Object parsed = this.parseTrades(rawTrades, marketNew, since, limit);
                    results = this.arrayConcat(results, parsed);
                }
                results = this.sortBy2(results, "timestamp", "id");
                return this.filterBySinceLimit(results, since, limit, "timestamp");
            }
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTradesV4
        //
        //     {
        //       "tradeID": 158056419,
        //       "price": "9186.13",
        //       "quote_volume": "0.0021",
        //       "base_volume": "9186.13",
        //       "trade_timestamp": 1594391747,
        //       "type": "sell"
        //     }
        //
        // orderTrades (v4Private)
        //
        //     {
        //         "time": 1593342324.613711,
        //         "fee": "0.00000419198",
        //         "price": "0.00000701",
        //         "amount": "598",
        //         "id": 149156519, // trade id
        //         "dealOrderId": 3134995325, // orderId
        //         "clientOrderId": "customId11",
        //         "role": 2, // 1 = maker, 2 = taker
        //         "deal": "0.00419198" // amount in money
        //         "feeAsset": "USDT"
        //     }
        //
        // fetchMyTrades
        //
        //      {
        //          "id": 1343815269,
        //          "clientOrderId": '',
        //          "time": 1641051917.532965,
        //          "side": "sell",
        //          "role": 2,
        //          "amount": "9.986",
        //          "price": "0.9995",
        //          "deal": "9.981007",
        //          "fee": "0.009981007",
        //          "orderId": 58166729555,
        //          "feeAsset": "USDT"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        market = this.safeMarket(null, market);
        Object timestamp = this.safeTimestamp2(trade, "time", "trade_timestamp");
        Object orderId = this.safeString2(trade, "dealOrderId", "orderId");
        Object cost = this.safeString(trade, "deal");
        Object price = this.safeString(trade, "price");
        Object amount = this.safeString2(trade, "amount", "quote_volume");
        Object id = this.safeString2(trade, "id", "tradeID");
        Object side = this.safeString2(trade, "type", "side");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object role = this.safeInteger(trade, "role");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(role, null)))
        {
            takerOrMaker = ((Helpers.isTrue((Helpers.isEqual(role, 1))))) ? "maker" : "taker";
        }
        Object fee = null;
        Object feeCost = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", WhitebitCore.this.safeCurrencyCode(WhitebitCore.this.safeString(trade, "feeAsset")) );
            }};
        }
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", WhitebitCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", id );
            put( "order", orderId );
            put( "type", null );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "side", side );
            put( "price", price );
            put( "amount", amount );
            put( "cost", cost );
            put( "fee", finalFee );
        }}, market);
    }

    /**
     * @method
     * @name whitebit#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://docs.whitebit.com/public/http-v1/#kline
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
                put( "interval", WhitebitCore.this.safeString(WhitebitCore.this.timeframes, timeframe, timeframe) );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Object maxLimit = 1440;
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = maxLimit;
                }
                limit = Helpers.mathMin(limit, maxLimit);
                Object start = this.parseToInt(Helpers.divide(since, 1000));
                Helpers.addElementToObject(request, "start", start);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", Helpers.mathMin(limit, 1440));
            }
            Object response = (this.v1PublicGetKline(this.extend(request, parameters))).join();
            //
            //     {
            //         "success":true,
            //         "message":"",
            //         "result":[
            //             [1591488000,"0.025025","0.025025","0.025029","0.025023","6.181","0.154686629"],
            //             [1591488060,"0.025028","0.025033","0.025035","0.025026","8.067","0.201921167"],
            //             [1591488120,"0.025034","0.02505","0.02505","0.025034","20.089","0.503114696"],
            //         ]
            //     }
            //
            Object result = this.safeList(response, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(result, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     [
        //         1591488000,
        //         "0.025025",
        //         "0.025025",
        //         "0.025029",
        //         "0.025023",
        //         "6.181",
        //         "0.154686629"
        //     ]
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeTimestamp(ohlcv, 0), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 4), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 5)));
    }

