    /**
     * @method
     * @name whitebit#createOrder
     * @description create a trade order
     * @see https://docs.whitebit.com/private/http-trade-v4/#create-limit-order
     * @see https://docs.whitebit.com/private/http-trade-v4/#create-market-order
     * @see https://docs.whitebit.com/private/http-trade-v4/#create-buy-stock-market-order
     * @see https://docs.whitebit.com/private/http-trade-v4/#create-stop-limit-order
     * @see https://docs.whitebit.com/private/http-trade-v4/#create-stop-market-order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.cost] *market orders only* the cost of the order in units of the base currency
     * @param {float} [params.triggerPrice] The price at which a trigger order is triggered at
     * @param {bool} [params.postOnly] If true, the order will only be posted to the order book and not executed immediately
     * @param {string} [params.clientOrderId] a unique id for the order
     * @param {string} [params.marginMode] 'cross' or 'isolated', for margin trading, uses this.options.defaultMarginMode if not passed, defaults to undefined/None/null
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            final Object finalSide = side;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
                put( "side", finalSide );
            }};
            Object cost = null;
            var costparametersVariable = this.handleParamString(parameters, "cost");
            cost = ((java.util.List<Object>) costparametersVariable).get(0);
            parameters = ((java.util.List<Object>) costparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
            {
                if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(side, "buy"))) || Helpers.isTrue((!Helpers.isEqual(type, "market")))))
                {
                    throw new InvalidOrder((String)Helpers.add(this.id, " createOrder() cost is only supported for market buy orders")) ;
                }
                Helpers.addElementToObject(request, "amount", this.costToPrecision(symbol, cost));
            } else
            {
                Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
            }
            Object clientOrderId = this.safeString2(parameters, "clOrdId", "clientOrderId");
            if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
            {
                Object brokerId = this.safeString(this.options, "brokerId");
                if (Helpers.isTrue(!Helpers.isEqual(brokerId, null)))
                {
                    Helpers.addElementToObject(request, "clientOrderId", Helpers.add(brokerId, this.uuid16()));
                }
            } else
            {
                Helpers.addElementToObject(request, "clientOrderId", clientOrderId);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId")));
            }
            Object marketType = this.safeString(market, "type");
            Object isLimitOrder = Helpers.isEqual(type, "limit");
            Object isMarketOrder = Helpers.isEqual(type, "market");
            Object triggerPrice = this.safeNumberN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice", "activation_price")));
            Object isStopOrder = (!Helpers.isEqual(triggerPrice, null));
            Object postOnly = this.isPostOnly(isMarketOrder, false, parameters);
            var marginModequeryVariable = this.handleMarginModeAndParams("createOrder", parameters);
            var marginMode = ((java.util.List<Object>) marginModequeryVariable).get(0);
            var query = ((java.util.List<Object>) marginModequeryVariable).get(1);
            if (Helpers.isTrue(postOnly))
            {
                Helpers.addElementToObject(request, "postOnly", true);
            }
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(marginMode, null)) && Helpers.isTrue(!Helpers.isEqual(marginMode, "cross"))))
            {
                throw new NotSupported((String)Helpers.add(this.id, " createOrder() is only available for cross margin")) ;
            }
            parameters = this.omit(query, new java.util.ArrayList<Object>(java.util.Arrays.asList("postOnly", "triggerPrice", "stopPrice")));
            Object useCollateralEndpoint = Helpers.isTrue(!Helpers.isEqual(marginMode, null)) || Helpers.isTrue(Helpers.isEqual(marketType, "swap"));
            Object response = null;
            if (Helpers.isTrue(isStopOrder))
            {
                Helpers.addElementToObject(request, "activation_price", this.priceToPrecision(symbol, triggerPrice));
                if (Helpers.isTrue(isLimitOrder))
                {
                    // stop limit order
                    Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                    response = (this.v4PrivatePostOrderStopLimit(this.extend(request, parameters))).join();
                } else
                {
                    // stop market order
                    if (Helpers.isTrue(useCollateralEndpoint))
                    {
                        response = (this.v4PrivatePostOrderCollateralTriggerMarket(this.extend(request, parameters))).join();
                    } else
                    {
                        response = (this.v4PrivatePostOrderStopMarket(this.extend(request, parameters))).join();
                    }
                }
            } else
            {
                if (Helpers.isTrue(isLimitOrder))
                {
                    // limit order
                    Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                    if (Helpers.isTrue(useCollateralEndpoint))
                    {
                        response = (this.v4PrivatePostOrderCollateralLimit(this.extend(request, parameters))).join();
                    } else
                    {
                        response = (this.v4PrivatePostOrderNew(this.extend(request, parameters))).join();
                    }
                } else
                {
                    // market order
                    if (Helpers.isTrue(useCollateralEndpoint))
                    {
                        response = (this.v4PrivatePostOrderCollateralMarket(this.extend(request, parameters))).join();
                    } else
                    {
                        if (Helpers.isTrue(!Helpers.isEqual(cost, null)))
                        {
                            response = (this.v4PrivatePostOrderMarket(this.extend(request, parameters))).join();
                        } else
                        {
                            response = (this.v4PrivatePostOrderStockMarket(this.extend(request, parameters))).join();
                        }
                    }
                }
            }
            return this.parseOrder(response);
        });

    }

    /**
     * @method
     * @name whitebit#editOrder
     * @description edit a trade order
     * @see https://docs.whitebit.com/private/http-trade-v4/#modify-order
     * @param {string} id cancel order id
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} price the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> editOrder(Object id, Object symbol, Object type2, Object side2, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object amount = Helpers.getArg(optionalArgs, 0, null);
            Object price = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
            }};
            // Handle clientOrderId vs orderId (clientOrderId takes priority)
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "clientOrderId", clientOrderId);
            } else
            {
                Helpers.addElementToObject(request, "orderId", id);
            }
            // Handle amount vs total parameter based on order type and side
            Object triggerPrice = this.safeNumberN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice", "activationPrice")));
            Object isStopOrder = (!Helpers.isEqual(triggerPrice, null));
            // Handle activation price for stop orders
            if (Helpers.isTrue(isStopOrder))
            {
                Helpers.addElementToObject(request, "activation_price", this.priceToPrecision(symbol, triggerPrice));
            }
            Object isLimitOrder = Helpers.isEqual(type, "limit");
            Object total = this.safeNumber(parameters, "total");
            if (Helpers.isTrue(!Helpers.isEqual(total, null)))
            {
                Helpers.addElementToObject(request, "total", this.amountToPrecision(symbol, total));
            } else if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
            {
                if (Helpers.isTrue(isLimitOrder))
                {
                    // Limit orders always use amount parameter
                    Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
                } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "market")) && Helpers.isTrue(Helpers.isEqual(side, "buy"))))
                {
                    // Market buy orders use total parameter
                    Helpers.addElementToObject(request, "total", this.amountToPrecision(symbol, amount));
                } else
                {
                    // Market sell orders use amount parameter
                    Helpers.addElementToObject(request, "amount", this.amountToPrecision(symbol, amount));
                }
            }
            // Handle price parameter for limit orders
            if (Helpers.isTrue(!Helpers.isEqual(price, null)))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            // Ensure at least one modifiable parameter is provided
            Object hasModifiableParam = Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(amount, null))) || Helpers.isTrue((!Helpers.isEqual(price, null)))) || Helpers.isTrue((!Helpers.isEqual(triggerPrice, null)))) || Helpers.isTrue((!Helpers.isEqual(total, null)));
            if (!Helpers.isTrue(hasModifiableParam))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " editOrder() requires at least one of: amount, price, activationPrice, or total parameters")) ;
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId", "triggerPrice", "stopPrice", "activationPrice", "total")));
            Object response = (this.v4PrivatePostOrderModify(this.extend(request, parameters))).join();
            return this.parseOrder(response);
        });

    }

