    /**
     * @method
     * @name whitebit#fetchAccounts
     * @description fetch all the accounts associated with a profile
     * @see https://docs.whitebit.com/private/http-main-v4/#sub-account-list
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [account structures]{@link https://docs.ccxt.com/?id=account-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchAccounts(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object accounts = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            // Fetch sub-accounts
            //
            //     [
            //         {
            //             "id": "12345",
            //             "name": "SubAccount1",
            //             "status": "active",
            //             "permissions": ["trade", "withdraw"]
            //         }
            //     ]
            //
            Object subAccounts = (this.v4PrivatePostSubAccountList(parameters)).join();
            if (Helpers.isTrue(Helpers.isTrue(subAccounts) && Helpers.isTrue(Helpers.isArray(subAccounts))))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(subAccounts)); i++)
                {
                    Object subAccount = this.safeValue(subAccounts, i);
                    Object accountId = this.safeString(subAccount, "id");
                    Object accountName = this.safeString(subAccount, "name");
                    if (Helpers.isTrue(accountId))
                    {
    final Object finalAccountName = accountName;
                                            ((java.util.List<Object>)accounts).add(new java.util.HashMap<String, Object>() {{
                            put( "id", accountId );
                            put( "type", "subaccount" );
                            put( "name", Helpers.isTrue(finalAccountName) || Helpers.isTrue(Helpers.add("SubAccount ", accountId)) );
                            put( "code", null );
                            put( "info", subAccount );
                        }});
                    }
                }
            }
            return accounts;
        });

    }

    /**
     * @method
     * @name whitebit#setLeverage
     * @description set the level of leverage for a market
     * @see https://docs.whitebit.com/private/http-trade-v4/#change-collateral-account-leverage
     * @param {float} leverage the rate of leverage
     * @param {string} symbol unified market symbol
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setLeverage(Object leverage2, Object... optionalArgs)
    {
        final Object leverage3 = leverage2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object leverage = leverage3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                throw new NotSupported((String)Helpers.add(this.id, " setLeverage() does not allow to set per symbol")) ;
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isLessThan(leverage, 1))) || Helpers.isTrue((Helpers.isGreaterThan(leverage, 20)))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " setLeverage() leverage should be between 1 and 20")) ;
            }
            final Object finalLeverage = leverage;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "leverage", finalLeverage );
            }};
            return (this.v4PrivatePostCollateralAccountLeverage(this.extend(request, parameters))).join();
        });

    }

    /**
     * @method
     * @name whitebit#transfer
     * @description transfer currency internally between wallets on the same account
     * @see https://docs.whitebit.com/private/http-main-v4/#transfer-between-main-and-trade-balances
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from - main, spot, collateral
     * @param {string} toAccount account to transfer to - main, spot, collateral
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount, Object toAccount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object accountsByType = this.safeValue(this.options, "accountsByType");
            Object fromAccountId = this.safeString(accountsByType, fromAccount, fromAccount);
            Object toAccountId = this.safeString(accountsByType, toAccount, toAccount);
            Object amountString = this.currencyToPrecision(code, amount);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ticker", Helpers.GetValue(currency, "id") );
                put( "amount", amountString );
                put( "from", fromAccountId );
                put( "to", toAccountId );
            }};
            Object response = (this.v4PrivatePostMainAccountTransfer(this.extend(request, parameters))).join();
            //
            //    []
            //
            return this.parseTransfer(response, currency);
        });

    }

