    /**
     * @method
     * @name whitebit#withdraw
     * @description make a withdrawal
     * @see https://docs.whitebit.com/private/http-main-v4/#create-withdraw-request
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code); // check if it has canDeposit
            Object request = new java.util.HashMap<String, Object>() {{
                put( "ticker", Helpers.GetValue(currency, "id") );
                put( "amount", WhitebitCore.this.currencyToPrecision(code, amount) );
                put( "address", address );
            }};
            Object uniqueId = this.safeValue(parameters, "uniqueId");
            if (Helpers.isTrue(Helpers.isEqual(uniqueId, null)))
            {
                uniqueId = this.uuid22();
            }
            Helpers.addElementToObject(request, "uniqueId", uniqueId);
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "memo", tag);
            }
            if (Helpers.isTrue(this.isFiat(code)))
            {
                Object provider = this.safeValue(parameters, "provider");
                if (Helpers.isTrue(Helpers.isEqual(provider, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() requires a provider when the ticker is fiat")) ;
                }
                Helpers.addElementToObject(request, "provider", provider);
            }
            Object response = (this.v4PrivatePostMainAccountWithdraw(this.extend(request, parameters))).join();
            //
            // empty array with a success status
            // go to deposit/withdraw history and check you request status by uniqueId
            //
            //     []
            //
            final Object finalUniqueId = uniqueId;
            return this.extend(this.parseTransaction(response, currency), new java.util.HashMap<String, Object>() {{
                put( "id", finalUniqueId );
            }});
        });

    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //     {
        //         "address": "3ApEASLcrQtZpg1TsssFgYF5V5YQJAKvuE",                                              // deposit address
        //         "uniqueId": null,                                                                             // unique Id of deposit
        //         "transactionId": "a6d71d69-2b17-4ad8-8b15-2d686c54a1a5",
        //         "createdAt": 1593437922,                                                                      // timestamp of deposit
        //         "currency": "Bitcoin",                                                                        // deposit currency
        //         "ticker": "BTC",                                                                              // deposit currency ticker
        //         "method": 1,                                                                                  // called method 1 - deposit, 2 - withdraw
        //         "amount": "0.0006",                                                                           // amount of deposit
        //         "description": "",                                                                            // deposit description
        //         "memo": "",                                                                                   // deposit memo
        //         "fee": "0",                                                                                   // deposit fee
        //         "status": 15,                                                                                 // transactions status
        //         "network": null,                                                                              // if currency is multinetwork
        //         "transactionHash": "a275a514013e4e0f927fd0d1bed215e7f6f2c4c6ce762836fe135ec22529d886",        // deposit transaction hash
        //         "details": {
        //             "partial": {                                                                              // details about partially successful withdrawals
        //                 "requestAmount": "50000",                                                             // requested withdrawal amount
        //                 "processedAmount": "39000",                                                           // processed withdrawal amount
        //                 "processedFee": "273",                                                                // fee for processed withdrawal amount
        //                 "normalizeTransaction": ""                                                            // deposit id
        //             }
        //         },
        //         "confirmations": {                                                                            // if transaction status == 15 you can see this object
        //             "actual": 1,                                                                              // current block confirmations
        //             "required": 2                                                                             // required block confirmation for successful deposit
        //         }
        //         "centralized": false,
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        currency = this.safeCurrency(null, currency);
        Object address = this.safeString(transaction, "address");
        Object timestamp = this.safeTimestamp(transaction, "createdAt");
        Object currencyId = this.safeString(transaction, "ticker");
        Object status = this.safeString(transaction, "status");
        Object method = this.safeString(transaction, "method");
        final Object finalMethod = method;
        final Object finalCurrency = currency;
        return new java.util.HashMap<String, Object>() {{
            put( "id", WhitebitCore.this.safeString(transaction, "uniqueId") );
            put( "txid", WhitebitCore.this.safeString(transaction, "transactionId") );
            put( "timestamp", timestamp );
            put( "datetime", WhitebitCore.this.iso8601(timestamp) );
            put( "network", WhitebitCore.this.safeString(transaction, "network") );
            put( "addressFrom", ((Helpers.isTrue((Helpers.isEqual(finalMethod, "1"))))) ? address : null );
            put( "address", address );
            put( "addressTo", ((Helpers.isTrue((Helpers.isEqual(finalMethod, "2"))))) ? address : null );
            put( "amount", WhitebitCore.this.safeNumber(transaction, "amount") );
            put( "type", ((Helpers.isTrue((Helpers.isEqual(finalMethod, "1"))))) ? "deposit" : "withdrawal" );
            put( "currency", WhitebitCore.this.safeCurrencyCode(currencyId, finalCurrency) );
            put( "status", WhitebitCore.this.parseTransactionStatus(status) );
            put( "updated", null );
            put( "tagFrom", null );
            put( "tag", WhitebitCore.this.safeString(transaction, "memo") );
            put( "tagTo", null );
            put( "comment", WhitebitCore.this.safeString(transaction, "description") );
            put( "internal", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", WhitebitCore.this.safeNumber(transaction, "fee") );
                put( "currency", WhitebitCore.this.safeCurrencyCode(currencyId, finalCurrency) );
            }} );
            put( "info", transaction );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "1", "pending" );
            put( "2", "pending" );
            put( "3", "ok" );
            put( "4", "canceled" );
            put( "5", "pending" );
            put( "6", "pending" );
            put( "7", "ok" );
            put( "9", "canceled" );
            put( "10", "pending" );
            put( "11", "pending" );
            put( "12", "pending" );
            put( "13", "pending" );
            put( "14", "pending" );
            put( "15", "pending" );
            put( "16", "pending" );
            put( "17", "pending" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    /**
     * @method
     * @name whitebit#fetchDeposit
     * @description fetch information on a deposit
     * @see https://docs.whitebit.com/private/http-main-v4/#get-depositwithdraw-history
     * @param {string} id deposit id
     * @param {string} code not used by whitebit fetchDeposit ()
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDeposit(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = null;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "transactionMethod", 1 );
                put( "uniqueId", id );
                put( "limit", 1 );
                put( "offset", 0 );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
                Helpers.addElementToObject(request, "ticker", Helpers.GetValue(currency, "id"));
            }
            Object response = (this.v4PrivatePostMainAccountHistory(this.extend(request, parameters))).join();
            //
            //     {
            //         "limit": 100,
            //         "offset": 0,
            //         "records": [
            //             {
            //                 "address": "3ApEASLcrQtZpg1TsssFgYF5V5YQJAKvuE",                                              // deposit address
            //                 "uniqueId": null,                                                                             // unique Id of deposit
            //                 "createdAt": 1593437922,                                                                      // timestamp of deposit
            //                 "currency": "Bitcoin",                                                                        // deposit currency
            //                 "ticker": "BTC",                                                                              // deposit currency ticker
            //                 "method": 1,                                                                                  // called method 1 - deposit, 2 - withdraw
            //                 "amount": "0.0006",                                                                           // amount of deposit
            //                 "description": "",                                                                            // deposit description
            //                 "memo": "",                                                                                   // deposit memo
            //                 "fee": "0",                                                                                   // deposit fee
            //                 "status": 15,                                                                                 // transactions status
            //                 "network": null,                                                                              // if currency is multinetwork
            //                 "transactionHash": "a275a514013e4e0f927fd0d1bed215e7f6f2c4c6ce762836fe135ec22529d886",        // deposit transaction hash
            //                 "details": {
            //                     "partial": {                                                                              // details about partially successful withdrawals
            //                         "requestAmount": "50000",                                                             // requested withdrawal amount
            //                         "processedAmount": "39000",                                                           // processed withdrawal amount
            //                         "processedFee": "273",                                                                // fee for processed withdrawal amount
            //                         "normalizeTransaction": ""                                                            // deposit id
            //                     }
            //                 },
            //                 "confirmations": {                                                                            // if transaction status == 15 you can see this object
            //                     "actual": 1,                                                                              // current block confirmations
            //                     "required": 2                                                                             // required block confirmation for successful deposit
            //                 }
            //             },
            //             {...},
            //         ],
            //         "total": 300                                                                                             // total number of  transactions, use this for calculating ‘limit’ and ‘offset'
            //     }
            //
            Object records = this.safeValue(response, "records", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object first = this.safeDict(records, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parseTransaction(first, currency);
        });

    }

