    /**
     * @method
     * @name whitebit#fetchConvertTradeHistory
     * @description fetch the users history of conversion trades
     * @see https://docs.whitebit.com/private/http-trade-v4/#convert-history
     * @param {string} [code] the unified currency code
     * @param {int} [since] the earliest time in ms to fetch conversions for
     * @param {int} [limit] the maximum number of conversion structures to retrieve, default 20, max 200
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.until] the end time in ms
     * @param {string} [params.fromTicker] the currency that you sold and converted from
     * @param {string} [params.toTicker] the currency that you bought and converted into
     * @param {string} [params.quoteId] the quote id of the conversion
     * @returns {object[]} a list of [conversion structures]{@link https://docs.ccxt.com/?id=conversion-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchConvertTradeHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                Helpers.addElementToObject(request, "fromTicker", code);
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Object start = this.parseToInt(Helpers.divide(since, 1000));
                Helpers.addElementToObject(request, "from", this.numberToString(start));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            var requestparametersVariable = this.handleUntilOption("to", request, parameters, 0.001);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = (this.v4PrivatePostConvertHistory(this.extend(request, parameters))).join();
            //
            //     {
            //         "records": [
            //             {
            //                 "id": "1741105",
            //                 "path": [
            //                     {
            //                         "from": "USDT",
            //                         "to": "BTC",
            //                         "rate": "0.00001193"
            //                     }
            //                 ],
            //                 "date": 1741090757,
            //                 "give": "4",
            //                 "receive": "0.00004772",
            //                 "rate": "0.00001193"
            //             }
            //         ],
            //         "total": 1,
            //         "limit": 100,
            //         "offset": 0
            //     }
            //
            Object rows = this.safeList(response, "records", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseConversions(rows, code, "fromCurrency", "toCurrency", since, limit);
        });

    }

    public Object parseConversion(Object conversion, Object... optionalArgs)
    {
        //
        // fetchConvertQuote
        //
        //     {
        //         "give": "4",
        //         "receive": "0.00004762",
        //         "rate": "0.0000119",
        //         "id": "1740889",
        //         "expireAt": 1741090147,
        //         "from": "USDT",
        //         "to": "BTC"
        //     }
        //
        // createConvertTrade
        //
        //     {
        //         "finalGive": "4",
        //         "finalReceive": "0.00004772"
        //     }
        //
        // fetchConvertTradeHistory
        //
        //     {
        //         "id": "1741105",
        //         "path": [
        //             {
        //                 "from": "USDT",
        //                 "to": "BTC",
        //                 "rate": "0.00001193"
        //             }
        //         ],
        //         "date": 1741090757,
        //         "give": "4",
        //         "receive": "0.00004772",
        //         "rate": "0.00001193"
        //     }
        //
        Object fromCurrency = Helpers.getArg(optionalArgs, 0, null);
        Object toCurrency = Helpers.getArg(optionalArgs, 1, null);
        Object path = this.safeList(conversion, "path", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object first = this.safeDict(path, 0, new java.util.HashMap<String, Object>() {{}});
        Object fromPath = this.safeString(first, "from");
        Object toPath = this.safeString(first, "to");
        Object timestamp = this.safeTimestamp2(conversion, "date", "expireAt");
        Object fromCoin = this.safeString(conversion, "from", fromPath);
        Object fromCode = this.safeCurrencyCode(fromCoin, fromCurrency);
        Object toCoin = this.safeString(conversion, "to", toPath);
        Object toCode = this.safeCurrencyCode(toCoin, toCurrency);
        return new java.util.HashMap<String, Object>() {{
            put( "info", conversion );
            put( "timestamp", timestamp );
            put( "datetime", WhitebitCore.this.iso8601(timestamp) );
            put( "id", WhitebitCore.this.safeString(conversion, "id") );
            put( "fromCurrency", fromCode );
            put( "fromAmount", WhitebitCore.this.safeNumber2(conversion, "give", "finalGive") );
            put( "toCurrency", toCode );
            put( "toAmount", WhitebitCore.this.safeNumber2(conversion, "receive", "finalReceive") );
            put( "price", WhitebitCore.this.safeNumber(conversion, "rate") );
            put( "fee", null );
        }};
    }

